mapper.select:
SELECT b.booking_id, b.booking_date, b.start_slot, b.end_slot, b.description, b.status, u.user_id, u.real_name, u.student_id, u.dept_name, u.role FROM biz_booking b LEFT JOIN sys_user u ON b.user_id = u.user_id
AND b.status = #{status}
AND u.role = #{role}
AND u.real_name LIKE CONCAT('%', #{realName}, '%')
AND u.student_id LIKE CONCAT('%', #{studentId}, '%')
AND b.booking_date = #{bookingDate}
ORDER BY b.booking_date DESC, b.start_slot ASC

SELECT b.*, u.real_name AS realName, u.student_id AS studentId, r.room_number AS roomNumber FROM biz_booking b LEFT JOIN sys_user u ON b.user_id = u.user_id LEFT JOIN sys_room r ON b.room_id = r.room_id
AND ( u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.student_id LIKE CONCAT('%', #{keyword}, '%') OR r.room_number LIKE CONCAT('%', #{keyword}, '%') )
AND b.booking_date >= #{startDate}
AND b.booking_date <= #{endDate}
AND b.status = #{status}
AND b.usage_type = #{usageType}
ORDER BY b.create_time DESC
